mcp:tool-listener.mcp:parameters-schema:
{
    "type": "object",
    "properties": {
      "prompt": {
        "type": "string",
        "description": "Detailed description of the API endpoints, methods, parameters, and responses."
      },
      "language": {
        "type": "string",
        "enum": ["RAML 1.0", "OAS 3.0 (YAML)", "OAS 3.0 (JSON)"],
        "default": "RAML 1.0"
      },
      "title": {
        "type": "string",
        "description": "The title of the API"
      }
    },
    "required": ["prompt", "title"]
  }

ee:message.ee:set-payload:
%dw 2.0
output applicaion/json
---
{
   model:"claude-sonnet-5",
   max_tokens:4000,
   messages:[
      {
        role:"user",
        content:payload.prompt
      }
   ]
}

